diff --git a/npm-package/src/__tests__/injectDevToolsMiddleware.test.js b/npm-package/src/__tests__/injectDevToolsMiddleware.test.js
index ad90dd0..3d83804 100644
--- a/npm-package/src/__tests__/injectDevToolsMiddleware.test.js
+++ b/npm-package/src/__tests__/injectDevToolsMiddleware.test.js
@@ -64,4 +64,31 @@ describe('Inject to devtoolsMiddleware of React Native packager', () => {
       fs.readFileSync(path.join(modulePath, 'react-native-macos', middlewarePath), 'utf-8')
     ).toMatchSnapshot();
   });
+
+  test('inject / revert in @react-native-commonunity/cli (RN ^0.59.0-rc.0)', async () => {
+    const mDir = 'build/server/middleware';
+    const mPath = path.join(mDir, 'getDevToolsMiddleware.js');
+    const code = await fetch(
+      'https://unpkg.com/@react-native-community/cli@1.2.2/build/server/middleware/getDevToolsMiddleware.js'
+    ).then(res => res.text());
+    fs.ensureDirSync(path.join(modulePath, '@react-native-community/cli', mDir));
+    fs.outputFileSync(path.join(modulePath, '@react-native-community/cli', mPath), code);
+    fs.outputFileSync(
+      path.join(modulePath, 'react-native', 'package.json'),
+      JSON.stringify({
+        version: '0.59.0-rc.0',
+        name: 'react-native',
+      })
+    );
+
+    expect(code).toMatchSnapshot();
+    inject(modulePath, 'react-native');
+    expect(
+      fs.readFileSync(path.join(modulePath, '@react-native-community/cli', mPath), 'utf-8')
+    ).toMatchSnapshot();
+    revert(modulePath, 'react-native');
+    expect(
+      fs.readFileSync(path.join(modulePath, '@react-native-community/cli', mPath), 'utf-8')
+    ).toMatchSnapshot();
+  });
 });

